DROP FUNCTION IF EXISTS feguslocal.obtener_cuotasatrasadas_lista(p_id_cliente integer, p_id_load_local bigint) CASCADE;
CREATE OR REPLACE FUNCTION feguslocal.obtener_cuotasatrasadas_lista(p_id_cliente integer, p_id_load_local bigint)  RETURNS SETOF feguslocal.cuotasatrasadas  LANGUAGE plpgsql AS $function$ BEGIN     RETURN QUERY SELECT * FROM feguslocal.cuotasatrasadas t     WHERE t.id_cliente = p_id_cliente AND t.id_load_local = p_id_load_local; END; $function$ 
